mapper.select:
select m.model_id as modelId, m.model_key as modelKey, m.model_name as modelName, m.category_id as categoryId, c.category_name as categoryName, m.form_type as formType, m.form_id as formId, f.form_name as formName, m.visible_flag as visibleFlag, m.sort, m.description, m.published_definition_id as publishedDefinitionId, m.has_unpublished_changes as hasUnpublishedChanges, m.create_time as createTime, m.update_time as updateTime from t_bpm_model m left join t_bpm_category c on c.category_id = m.category_id and c.deleted_flag = 0 left join t_bpm_form f on f.form_id = m.form_id and f.deleted_flag = 0 where m.deleted_flag = #{queryForm.deletedFlag}
and m.model_key like concat('%', #{queryForm.modelKey}, '%')
and m.model_name like concat('%', #{queryForm.modelName}, '%')
and m.category_id = #{queryForm.categoryId}
and m.form_id = #{queryForm.formId}
and m.visible_flag = #{queryForm.visibleFlag}
order by m.sort asc, m.model_id desc

select *
from t_bpm_model
where 1 = 1

    and model_id = #{modelId}


    and model_key = #{modelKey}


    and deleted_flag = #{deletedFlag}

limit 1
